// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar, QrCode, Trash2 } from 'lucide-react'
import DatePicker from 'react-datepicker'
import { subDays } from 'date-fns'
import Etiqueta from './Etiqueta'
import { QRCodeSVG as QRCode } from 'qrcode.react'

export default function TelaEsterilizacao() {
  // fluxo em 5 passos
  const [step, setStep] = useState(1)
  const [tipoOp, setTipoOp] = useState(null)       // 'entrada' ou 'saida'

  // estados originais
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [alunoNome, setAlunoNome] = useState('')
  const [pinValidated, setPinValidated] = useState(false)
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')
  const datePickerRef = useRef(null)
  const [printData, setPrintData] = useState(null)
  const componentRef = useRef(null)
  const storedUser = JSON.parse(localStorage.getItem('user') || '{}')
  const usuarioLogadoNome = storedUser.nome || ''

  const BADGE_STYLES = [
    'bg-blue-100 text-blue-800',
    'bg-green-100 text-green-800',
    'bg-yellow-100 text-yellow-800',
    'bg-purple-100 text-purple-800',
  ]

  // Imprime etiqueta em janela separada
  useEffect(() => {
    if (!printData) return
    const area = document.getElementById('area-impressao')
    if (!area) return
    const html = `
      <html>
        <head>
          <title>Impressão de Etiqueta</title>
          <style>body{margin:0;padding:8mm;font-family:sans-serif}</style>
        </head>
        <body>${area.innerHTML}</body>
      </html>`
    const w = window.open('', '_blank', 'width=600,height=400')
    w.document.write(html)
    w.document.close()
    w.focus()
    w.print()
    setPrintData(null)
    setTimeout(() => w.close(), 500)
  }, [printData])

  // Carrega caixas para autocomplete
  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // Histórico — busca últimas 30 dias
  const fetchHistory = useCallback(() => {
    if (!pinValidated || !alunoNome) return
    axios.get('/api/movimentacoes')
      .then(res => {
        const hoje = new Date()
        const from = subDays(hoje, 30).toISOString().slice(0, 10)
        const to = hoje.toISOString().slice(0, 10)
        setHistorico(res.data.filter(m => {
          const dia = new Date(m.criado_em).toISOString().slice(0, 10)
          return m.alunoNome === alunoNome && dia >= from && dia <= to
        }))
      })
      .catch(() => setHistorico([]))
  }, [alunoNome, pinValidated])

  useEffect(() => {
    fetchHistory()
  }, [fetchHistory])

  // Passo 1 → escolha de operação
  const handleStart = op => {
    setTipoOp(op)
    setStep(2)
  }

  // Passo 2 → validação de PIN
  const validarPin = () => {
    if (alunoPin.trim().length !== 4) {
      toast.warn('PIN deve ter 4 dígitos.', { autoClose: 5000 })
      return
    }
    axios.get(`/api/alunos/pin/${alunoPin}`)
      .then(res => {
        setAlunoNome(res.data.nome)
        setPinValidated(true)
        toast.success(`PIN validado: ${res.data.nome}`, { autoClose: 5000 })
        setStep(3)
        fetchHistory()
      })
      .catch(() => toast.error('Aluno não encontrado por este PIN.', { autoClose: 5000 }))
  }

  // Sugestões de caixas
  const suggestions = codigo
    ? allCaixas.filter(c =>
        c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
        c.codigo_barras.includes(codigo)
      ).slice(0, 5)
    : []

  const addCaixa = c => {
    setCaixas(p => [...p, c])
    toast.success(`Caixa adicionada: ${c.nome}`, { autoClose: 5000 })
    setCodigo('')
  }

  const buscarCaixa = () => {
    const e = allCaixas.find(c =>
      c.codigo_barras === codigo ||
      c.nome.toLowerCase().includes(codigo.toLowerCase())
    )
    if (!e) return toast.error('Caixa não encontrada.', { autoClose: 5000 })
    addCaixa(e)
  }

  const removerCaixa = id => {
    setCaixas(p => {
      const nxt = [...p]
      const i = nxt.findIndex(x => x.id === id)
      if (i >= 0) nxt.splice(i, 1)
      return nxt
    })
  }

  // Passo 3 → confirmar entrada/saída
  const operar = async tipo => {
    if (!pinValidated) {
      toast.warn('Valide o PIN antes.', { autoClose: 5000 })
      return
    }
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.', { autoClose: 5000 })
      return
    }
    if (tipo === 'saida') {
      const inv = caixas.filter(c => {
        const h = historico.filter(m => m.caixa_id === c.id)
        return !h.length || h[0].tipo !== 'entrada'
      })
      if (inv.length) {
        inv.forEach(c =>
          toast.error(`Não é possível dar saída da caixa "${c.nome}" sem entrada.`, { autoClose: 5000 })
        )
        return
      }
    }
    try {
      await Promise.all(caixas.map(c =>
        axios.post(`/api/movimentacoes/${tipo}`, { caixa_id: c.id, aluno_pin: alunoPin })
      ))
      toast.success(
        `${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada para ${alunoNome}!`,
        { autoClose: 5000 }
      )
      setStep(5)
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`, { autoClose: 5000 })
    }
  }

  // Passo 4 → impressão de etiquetas
  const handlePrint = c => {
    setPrintData({
      alunoNome,
      caixaId: c.id,
      caixaNome: c.nome,
      criadoEm: new Date().toISOString(),
      recebidoPor: usuarioLogadoNome,
    })
  }

  // Excluir histórico
  const handleDeleteHistory = async id => {
    if (!window.confirm('Deseja realmente excluir esta movimentação?')) return
    try {
      await axios.delete(`/api/movimentacoes/${id}`)
      setHistorico(p => p.filter(m => m.id !== id))
      toast.success('Movimentação excluída.', { autoClose: 5000 })
    } catch {
      toast.error('Erro ao excluir movimentação.', { autoClose: 5000 })
    }
  }

  // Agrupa caixas e calcula estoque
  const caixaCounts = caixas.reduce((a, c) => {
    if (!a[c.id]) a[c.id] = { ...c, qty: 1 }
    else a[c.id].qty++
    return a
  }, {})
  const uniqueCaixas = Object.values(caixaCounts)
  const stockByBox = {}
  historico.forEach(m => {
    stockByBox[m.caixaNome] = (stockByBox[m.caixaNome] || 0) + (m.tipo === 'entrada' ? 1 : -1)
  })

  return (
    <div className="max-w-4xl mx-auto py-10 px-4 space-y-6">

      {/* Passo 1 */}
      {step === 1 && (
        <div className="bg-white rounded-2xl shadow p-6 text-center space-y-4">
          <h3 className="text-xl font-bold">Controle de Esterilização</h3>
          <button onClick={() => handleStart('entrada')}
            className="w-full py-2 bg-green-600 text-white rounded-full">ENTRADA</button>
          <button onClick={() => handleStart('saida')}
            className="w-full py-2 bg-red-600 text-white rounded-full">SAÍDA</button>
        </div>
      )}

      {/* Passo 2 */}
      {step === 2 && (
        <div className="bg-white rounded-2xl shadow p-6 space-y-4">
          <h3 className="font-semibold">Informe o PIN do aluno</h3>
          <input type="password" maxLength={4}
            value={alunoPin}
            onChange={e => setAlunoPin(e.target.value.replace(/\D/g, ''))}
            onKeyDown={e => e.key === 'Enter' && validarPin()}
            className="w-full border rounded px-3 py-2" />
          <button onClick={validarPin}
            className="w-full py-2 bg-blue-600 text-white rounded-full">Validar PIN</button>
        </div>
      )}

      {/* Passo 3 */}
      {step === 3 && (
        <>
          {/* busca/adicionar caixas */}
          <div className="bg-white rounded-2xl shadow p-6">
            <div className="relative flex flex-col md:flex-row gap-4">
              <input
                type="text"
                placeholder="Código ou nome da caixa"
                value={codigo}
                onChange={e => setCodigo(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), buscarCaixa())}
                className="flex-1 border rounded px-3 py-2"
              />
              <button onClick={buscarCaixa}
                className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full">
                Adicionar
              </button>
              {suggestions.length > 0 && (
                <ul className="absolute z-20 bg-white border rounded shadow mt-12 w-full md:w-auto max-h-40 overflow-y-auto">
                  {suggestions.map(c => (
                    <li key={c.id}
                      className="px-3 py-2 hover:bg-gray-100 cursor-pointer"
                      onClick={() => addCaixa(c)}>
                      {c.nome} ({c.codigo_barras})
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>

          {/* caixas selecionadas */}
          {uniqueCaixas.length > 0 && (
            <div className="bg-white rounded-2xl shadow p-6">
              <h3 className="font-medium mb-2">Caixas selecionadas</h3>
              <div className="flex flex-wrap gap-2">
                {uniqueCaixas.map(c => (
                  <div key={c.id} className="bg-gray-100 px-3 py-1 rounded-full flex items-center">
                    {c.nome} ({c.qty})
                    <button onClick={() => removerCaixa(c.id)} className="ml-2 text-gray-500">×</button>
                  </div>
                ))}
              </div>
              <button onClick={() => operar(tipoOp)}
                className={`mt-4 w-full py-2 ${tipoOp === 'entrada' ? 'bg-green-600' : 'bg-red-600'} text-white rounded-full`}>
                Confirmar {tipoOp.toUpperCase()}
              </button>
            </div>
          )}
        </>
      )}

      {/* Passo 4 (impressão) */}
      {step === 5 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="font-medium mb-2">Etiquetas para impressão</h3>
          <div className="flex flex-wrap gap-4">
            {uniqueCaixas.map(c => (
              <div key={c.id} className="flex items-center gap-2 bg-gray-50 p-2 rounded-full">
                <span className="font-medium">{c.nome}</span>
                <button onClick={() => handlePrint(c)} className="no-print" title="Imprimir">
                  <QrCode size={18} />
                </button>
              </div>
            ))}
          </div>
          <button onClick={() => { setStep(1); setCaixas([]); setAlunoPin(''); setPinValidated(false) }}
            className="mt-4 w-full py-2 bg-gray-300 text-black rounded-full">
            Finalizar
          </button>
        </div>
      )}

      {/* Impressão oculta */}
      {printData && (
        <div id="area-impressao" style={{ position: 'absolute', left: '-10000px', top: '-10000px' }}>
          <Etiqueta
            ref={componentRef}
            alunoNome={printData.alunoNome}
            caixaId={printData.caixaId}
            criadoEm={printData.criadoEm}
            recebidoPor={printData.recebidoPor}
          />
        </div>
      )}

      {/* Histórico (presente em todos steps ≥ 3) */}
      {step > 2 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="font-bold mb-4">Histórico (últimos 30 dias)</h3>
          <div className="flex flex-col md:flex-row justify-between gap-2 mb-4">
            <input
              type="text"
              placeholder="Pesquisar..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              type="button"
              className="p-2 hover:bg-gray-100 rounded-full"
              onClick={() => datePickerRef.current.setOpen(true)}
            >
              <Calendar size={20} className="text-gray-600" />
            </button>
            <DatePicker
              ref={datePickerRef}
              selected={filterDate ? new Date(filterDate) : null}
              onChange={d => setFilterDate(d.toISOString().slice(0, 10))}
              customInput={<></>}
              locale="pt-BR"
              dateFormat="dd/MM/yyyy"
            />
          </div>
          <div className="hidden md:grid grid-cols-6 gap-4 text-sm font-semibold text-gray-600 border-b pb-2 mb-2">
            <div>Caixa</div><div>Tipo</div><div>Aluno</div><div>Operador</div><div>Data</div><div className="text-right">Ações</div>
          </div>
          {(() => {
            const fil = historico.filter(m => {
              const txt = searchTerm.toLowerCase()
              const okTxt = [m.caixaNome, m.tipo, m.alunoNome, m.operadorNome]
                .some(f => f.toLowerCase().includes(txt))
              const okDate = !filterDate || new Date(m.criado_em).toISOString().slice(0, 10) === filterDate
              return okTxt && okDate
            })
            if (!fil.length) return <p className="text-gray-500">Nenhuma movimentação.</p>
            return (
              <div className="space-y-4">
                {fil.map(m => (
                  <div key={m.id} className="grid grid-cols-1 md:grid-cols-6 gap-4 bg-gray-50 rounded-xl p-4 items-center">
                    <div className="font-medium">{m.caixaNome}</div>
                    <div>{m.tipo}</div>
                    <div>{m.alunoNome}</div>
                    <div>{m.operadorNome}</div>
                    <div>{new Date(m.criado_em).toLocaleString()}</div>
                    <div className="flex justify-end gap-4 items-center">
                      <button onClick={() => handlePrint({
                        caixaId: m.caixa_id,
                        caixaNome: m.caixaNome,
                        criadoEm: m.criado_em,
                        alunoNome
                      })}
                        className="no-print cursor-pointer text-blue-600"
                        title="Reimprimir etiqueta"
                      >
                        <QrCode size={18} />
                      </button>
                      <Trash2
                        onClick={() => handleDeleteHistory(m.id)}
                        className="cursor-pointer text-red-600"
                        size={18}
                        title="Excluir movimentação"
                      />
                    </div>
                  </div>
                ))}
              </div>
            )
          })()}
        </div>
      )}
    </div>
  )
}
